use ferrotorch_nn::StateDict;
use ferrotorch_serialize::{
    GgmlType, GgufFile, GgufMetadata, GgufTensorInfo, GgufValue, OnnxExportConfig, PickleValue,
    TrainingCheckpoint, dequantize_gguf_tensor, export_from_program, export_ir_graph_to_onnx,
    export_onnx, ir_graph_to_onnx, load_checkpoint, load_gguf, load_gguf_mmap,
    load_gguf_state_dict, load_gguf_state_dict_mmap, load_pytorch_state_dict, load_safetensors,
    load_state_dict, parse_gguf_bytes, parse_pickle, save_checkpoint, save_pytorch,
    save_safetensors, save_state_dict, validate_checkpoint,
};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// cascade_skip macro
// ---------------------------------------------------------------------------

/// Print a skip diagnostic and return early. Never panics.
/// Kept for future cascade_skip additions; currently all items are covered.
#[allow(unused_macros)]
macro_rules! cascade_skip {
    ($reason:literal) => {{
        eprintln!("  [cascade_skip] {} — {}", module_path!(), $reason);
        return;
    }};
}

// ---------------------------------------------------------------------------
// Tensor construction helpers
// ---------------------------------------------------------------------------

fn make_f32(data: Vec<f32>, shape: Vec<usize>) -> Tensor<f32> {
    let storage = TensorStorage::cpu(data);
    Tensor::from_storage(storage, shape, false).unwrap()
}

fn make_f64(data: Vec<f64>, shape: Vec<usize>) -> Tensor<f64> {
    let storage = TensorStorage::cpu(data);
    Tensor::from_storage(storage, shape, false).unwrap()
}

fn state32(pairs: &[(&str, Vec<f32>, Vec<usize>)]) -> StateDict<f32> {
    let mut m: StateDict<f32> = HashMap::new();
    for (name, data, shape) in pairs {
        m.insert((*name).to_string(), make_f32(data.clone(), shape.clone()));
    }
    m
}

fn state64(pairs: &[(&str, Vec<f64>, Vec<usize>)]) -> StateDict<f64> {
    let mut m: StateDict<f64> = HashMap::new();
    for (name, data, shape) in pairs {
        m.insert((*name).to_string(), make_f64(data.clone(), shape.clone()));
    }
    m
}

// ---------------------------------------------------------------------------
// Fixture deserialization
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
struct FixtureFile {
    metadata: FixtureMetadata,
    save_safetensors: Vec<serde_json::Value>,
    load_safetensors: Vec<serde_json::Value>,
    save_pytorch: Vec<serde_json::Value>,
    load_pytorch: Vec<serde_json::Value>,
    parse_pickle: Vec<serde_json::Value>,
    validate_checkpoint: Vec<serde_json::Value>,
    save_state_dict: Vec<serde_json::Value>,
    save_checkpoint: Vec<serde_json::Value>,
    training_checkpoint: Vec<serde_json::Value>,
}

#[derive(Debug, Deserialize)]
struct FixtureMetadata {
    torch_version: String,
    safetensors_version: String,
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    generated_at: String,
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    conformance_note: String,
}

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Regenerate via \
             scripts/regenerate_serialize_fixtures.py",
            p.display()
        )
    });
    serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()))
}

fn fixture_by_kind<'a>(arr: &'a [serde_json::Value], kind: &str) -> Option<&'a serde_json::Value> {
    arr.iter()
        .find(|v| v.get("kind").and_then(|k| k.as_str()) == Some(kind))
}

