/// save_safetensors + load_safetensors round-trips an f32 2D tensor
/// with byte-exact data preservation.
#[test]
fn save_load_safetensors_f32_2d() {
    let file = load_fixtures();
    let f = fixture_by_kind(&file.save_safetensors, "round_trip_f32_2d")
        .expect("round_trip_f32_2d fixture not found");

    let data: Vec<f32> = f["data_f32"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_f64().unwrap() as f32)
        .collect();
    let shape: Vec<usize> = f["shape"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap() as usize)
        .collect();
    let name = f["tensor_name"].as_str().unwrap();
    let expected_numel = f["expected_numel"].as_u64().unwrap() as usize;
    let expected_bytes = f["expected_byte_length"].as_u64().unwrap() as usize;

    let state = state32(&[(name, data.clone(), shape.clone())]);
    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("model.safetensors");

    save_safetensors(&state, &path).expect("save_safetensors failed");

    let file_bytes = std::fs::metadata(&path).unwrap().len() as usize;
    assert!(
        file_bytes >= expected_bytes,
        "safetensors file too small: {file_bytes} < {expected_bytes} tensor bytes"
    );

    let loaded: StateDict<f32> = load_safetensors(&path).expect("load_safetensors failed");
    let t = &loaded[name];
    assert_eq!(t.shape(), shape.as_slice(), "[{name}] shape mismatch");
    assert_eq!(t.numel(), expected_numel, "[{name}] numel mismatch");

    let got = t.data().unwrap();
    assert_eq!(got.len(), data.len(), "[{name}] data length mismatch");
    for (i, (&g, &exp)) in got.iter().zip(data.iter()).enumerate() {
        assert!(
            (g - exp).abs() < 1e-6,
            "[{name}][{i}]: expected {exp}, got {g}"
        );
    }
    eprintln!(
        "  save_load_safetensors_f32_2d: {} tensor, {} elements, {} bytes",
        name, expected_numel, expected_bytes
    );
}

