/// save_safetensors preserves NaN and Inf values.
#[test]
fn save_load_safetensors_nan_inf() {
    let file = load_fixtures();
    let _f = fixture_by_kind(&file.save_safetensors, "nan_inf_preserved")
        .expect("nan_inf_preserved fixture not found");

    let data = vec![f32::NAN, f32::INFINITY, f32::NEG_INFINITY];
    let state = state32(&[("special", data.clone(), vec![3])]);
    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("special.safetensors");

    save_safetensors(&state, &path).expect("save_safetensors NaN/Inf failed");
    let loaded: StateDict<f32> = load_safetensors(&path).expect("load_safetensors NaN/Inf failed");

    let got = loaded["special"].data().unwrap();
    assert!(got[0].is_nan(), "NaN not preserved");
    assert!(got[1].is_infinite() && got[1] > 0.0, "+Inf not preserved");
    assert!(got[2].is_infinite() && got[2] < 0.0, "-Inf not preserved");
}

