/// save_safetensors writes keys in sorted order.
#[test]
fn save_safetensors_deterministic_key_ordering() {
    let file = load_fixtures();
    let f = fixture_by_kind(&file.save_safetensors, "multi_tensor_sorted_keys")
        .expect("multi_tensor_sorted_keys fixture not found");

    let tensors = f["tensors"].as_array().unwrap();
    let expected_order: Vec<&str> = f["expected_key_order"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_str().unwrap())
        .collect();

    let mut state: StateDict<f32> = HashMap::new();
    for t in tensors {
        let name = t["name"].as_str().unwrap().to_string();
        let data: Vec<f32> = t["data_f32"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_f64().unwrap() as f32)
            .collect();
        let shape: Vec<usize> = t["shape"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap() as usize)
            .collect();
        state.insert(name, make_f32(data, shape));
    }

    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("multi.safetensors");
    save_safetensors(&state, &path).expect("save_safetensors multi failed");

    // Load with safetensors raw to check key order.
    let loaded: StateDict<f32> = load_safetensors(&path).expect("load multi failed");
    let mut keys: Vec<&str> = loaded.keys().map(String::as_str).collect();
    keys.sort();
    assert_eq!(keys, expected_order, "key order mismatch after round-trip");
}

/// load_safetensors returns DtypeMismatch when the file dtype does not match T.
#[test]
fn load_safetensors_dtype_mismatch_error() {
    let file = load_fixtures();
    let f = fixture_by_kind(&file.load_safetensors, "dtype_mismatch_error")
        .expect("dtype_mismatch_error fixture not found");

    let expected_error = f["expected_error"].as_str().unwrap();
    assert_eq!(expected_error, "DtypeMismatch");

    // Write an f32 file.
    let state: StateDict<f32> = state32(&[("x", vec![1.0, 2.0], vec![2])]);
    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("dtype.safetensors");
    save_safetensors(&state, &path).expect("save failed");

    // Attempt to load as f64 — must fail with DtypeMismatch.
    let result: Result<StateDict<f64>, _> = load_safetensors(&path);
    assert!(
        result.is_err(),
        "load_safetensors should fail when loading f32 file as f64"
    );
    assert!(
        matches!(result.unwrap_err(), FerrotorchError::DtypeMismatch { .. }),
        "expected DtypeMismatch error"
    );
}

