/// save_pytorch produces a ZIP with the required structure and pickle content.
#[test]
fn save_pytorch_zip_structure_and_pickle() {
    let file = load_fixtures();
    let f = fixture_by_kind(&file.save_pytorch, "round_trip_f32")
        .expect("round_trip_f32 fixture not found");

    let data: Vec<f32> = f["data_f32"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_f64().unwrap() as f32)
        .collect();
    let shape: Vec<usize> = f["shape"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap() as usize)
        .collect();
    let name = f["tensor_name"].as_str().unwrap();
    let expected_contains: Vec<&str> = f["expected_pickle_contains"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_str().unwrap())
        .collect();
    let expected_storage_bytes = f["expected_storage_bytes"].as_u64().unwrap() as usize;

    let state = state32(&[(name, data.clone(), shape.clone())]);
    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("model.pt");

    save_pytorch(&state, &path).expect("save_pytorch failed");

    let zip_file = std::fs::File::open(&path).unwrap();
    let mut archive = zip::ZipArchive::new(zip_file).expect("ZIP open failed");

    let names: Vec<String> = (0..archive.len())
        .map(|i| archive.by_index(i).unwrap().name().to_string())
        .collect();

    assert!(
        names.contains(&"archive/data.pkl".to_string()),
        "archive/data.pkl missing from ZIP"
    );
    assert!(
        names.iter().any(|n| n.starts_with("archive/data/")),
        "no archive/data/* storage blob in ZIP"
    );

    let pkl_bytes = {
        let mut e = archive.by_name("archive/data.pkl").unwrap();
        let mut v = Vec::new();
        e.read_to_end(&mut v).unwrap();
        v
    };

    // Pickle protocol 2 header.
    assert_eq!(
        pkl_bytes[0], 0x80,
        "pickle must start with PROTO opcode (0x80)"
    );
    assert_eq!(pkl_bytes[1], 0x02, "pickle must be protocol 2 (0x02)");
    // STOP opcode.
    assert_eq!(
        *pkl_bytes.last().unwrap(),
        0x2e,
        "pickle must end with STOP (0x2e)"
    );

    let pkl_str = String::from_utf8_lossy(&pkl_bytes);
    for token in &expected_contains {
        assert!(
            pkl_str.contains(token),
            "pickle missing expected token: {token:?}"
        );
    }

    // Verify storage blob size.
    let blob = {
        let mut e = archive.by_name("archive/data/0").unwrap();
        let mut v = Vec::new();
        e.read_to_end(&mut v).unwrap();
        v
    };
    assert_eq!(
        blob.len(),
        expected_storage_bytes,
        "storage blob size mismatch: expected {expected_storage_bytes}, got {}",
        blob.len()
    );

    // Verify tensor bytes are correct (little-endian f32).
    let values: Vec<f32> = blob
        .chunks_exact(4)
        .map(|c| f32::from_le_bytes(c.try_into().unwrap()))
        .collect();
    for (i, (&got, &exp)) in values.iter().zip(data.iter()).enumerate() {
        assert!(
            (got - exp).abs() < 1e-7,
            "storage blob[{i}]: expected {exp}, got {got}"
        );
    }

    eprintln!(
        "  save_pytorch_zip_structure_and_pickle: {} entries in ZIP, {} pickle bytes, {} storage bytes",
        names.len(),
        pkl_bytes.len(),
        expected_storage_bytes
    );
}

