/// save_pytorch writes keys in sorted (alphabetical) order in the pickle.
#[test]
fn save_pytorch_deterministic_key_ordering() {
    let file = load_fixtures();
    let f = fixture_by_kind(&file.save_pytorch, "deterministic_ordering")
        .expect("deterministic_ordering fixture not found");

    let tensors = f["tensors"].as_array().unwrap();
    let expected_order: Vec<&str> = f["expected_key_order"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_str().unwrap())
        .collect();

    let mut state: StateDict<f32> = HashMap::new();
    for t in tensors {
        let name = t["name"].as_str().unwrap().to_string();
        let data: Vec<f32> = t["data_f32"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_f64().unwrap() as f32)
            .collect();
        let shape: Vec<usize> = t["shape"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap() as usize)
            .collect();
        state.insert(name, make_f32(data, shape));
    }

    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("order.pt");
    save_pytorch(&state, &path).expect("save_pytorch order failed");

    let zip_file = std::fs::File::open(&path).unwrap();
    let mut archive = zip::ZipArchive::new(zip_file).unwrap();
    let mut pkl_entry = archive.by_name("archive/data.pkl").unwrap();
    let mut pkl_bytes = Vec::new();
    pkl_entry.read_to_end(&mut pkl_bytes).unwrap();
    let pkl_str = String::from_utf8_lossy(&pkl_bytes);

    let positions: Vec<usize> = expected_order
        .iter()
        .map(|key| {
            pkl_str
                .find(key)
                .unwrap_or_else(|| panic!("key {key:?} not found in pickle"))
        })
        .collect();

    for i in 1..positions.len() {
        assert!(
            positions[i - 1] < positions[i],
            "key order violated: {:?} ({}) appears after {:?} ({})",
            expected_order[i - 1],
            positions[i - 1],
            expected_order[i],
            positions[i]
        );
    }
}

/// load_pytorch_state_dict round-trips a save_pytorch file.
#[test]
fn load_pytorch_state_dict_round_trip() {
    let file = load_fixtures();
    let f =
        fixture_by_kind(&file.load_pytorch, "round_trip").expect("round_trip fixture not found");

    let tensors = f["tensors"].as_array().unwrap();
    let mut state: StateDict<f32> = HashMap::new();
    for t in tensors {
        let name = t["name"].as_str().unwrap().to_string();
        let data: Vec<f32> = t["data_f32"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_f64().unwrap() as f32)
            .collect();
        let shape: Vec<usize> = t["shape"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap() as usize)
            .collect();
        state.insert(name, make_f32(data, shape));
    }

    let dir = tempfile::tempdir().expect("tempdir");
    let path = dir.path().join("rt.pt");
    save_pytorch(&state, &path).expect("save_pytorch failed");

    let loaded: StateDict<f32> = load_pytorch_state_dict(&path).expect("load_pytorch failed");
    assert_eq!(loaded.len(), state.len(), "tensor count mismatch");

    for t in tensors {
        let name = t["name"].as_str().unwrap();
        let orig_data: Vec<f32> = t["data_f32"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_f64().unwrap() as f32)
            .collect();
        let orig_shape: Vec<usize> = t["shape"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap() as usize)
            .collect();

        let lt = &loaded[name];
        assert_eq!(lt.shape(), orig_shape.as_slice(), "[{name}] shape mismatch");
        let got = lt.data().unwrap();
        for (i, (&g, &exp)) in got.iter().zip(orig_data.iter()).enumerate() {
            assert!(
                (g - exp).abs() < 1e-6,
                "[{name}][{i}]: expected {exp}, got {g}"
            );
        }
    }
}

